export default function Listing2() {
  const containerRef = useRef<HTMLDivElement>(null)
  const [scrollPosition, setScrollPosition] = useState(0)
  const [maxScroll, setMaxScroll] = useState(0)

  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current) {
        const { scrollWidth, clientWidth } = containerRef.current
        setMaxScroll(scrollWidth - clientWidth)
      }
    }

    handleResize()
    window.addEventListener('resize', handleResize)
    return () => window.removeEventListener('resize', handleResize)
  }, [])

  const handleScroll = (direction: 'left' | 'right') => {
    if (containerRef.current) {
      const scrollAmount = direction === 'left' ? -248 : 248
      const newPosition = Math.min(Math.max(0, scrollPosition + scrollAmount), maxScroll)
      containerRef.current.scrollTo({ left: newPosition, behavior: 'smooth' })
      setScrollPosition(newPosition)
    }
  }

  const onScroll = () => {
    if (containerRef.current) {
      setScrollPosition(containerRef.current.scrollLeft)
    }
  }

  return (
    <section className='relative py-16' aria-label='Categories'>
      <div className='mx-auto w-full max-w-7xl px-4 sm:px-6 lg:px-8'>
        {/* Section Header */}
        <div className='mb-12 text-center'>
          <div className='relative mb-4 inline-block'>
            <h2 className='text-foreground text-3xl font-bold text-balance sm:text-4xl'>Categories</h2>
          </div>
          <p className='text-muted-foreground mx-auto mt-4 max-w-2xl text-base text-balance sm:text-lg'>
            Here are lots of interesting destinations to visit, but don't be confused - they're already grouped by
            category.
          </p>
        </div>

        {/* Categories Carousel */}
        <div className='relative w-full'>
          {/* Navigation Buttons */}
          <div className='absolute -start-8 top-1/2 z-10 -translate-y-1/2'>
            <Button
              variant='secondary'
              size='icon'
              className={`size-10 cursor-pointer rounded-full shadow-lg transition-opacity ${
                scrollPosition === 0 ? 'pointer-events-none opacity-40' : 'opacity-100'
              }`}
              onClick={() => handleScroll('left')}
              disabled={scrollPosition === 0}
              aria-label='Scroll left'
            >
              <ChevronLeft className='size-5' />
            </Button>
          </div>
          <div className='absolute -end-8 top-1/2 z-10 -translate-y-1/2'>
            <Button
              variant='secondary'
              size='icon'
              className={`size-10 cursor-pointer rounded-full shadow-lg transition-opacity ${
                scrollPosition >= maxScroll ? 'pointer-events-none opacity-40' : 'opacity-100'
              }`}
              onClick={() => handleScroll('right')}
              disabled={scrollPosition >= maxScroll}
              aria-label='Scroll right'
            >
              <ChevronRight className='size-5' />
            </Button>
          </div>

          {/* Scrollable Container */}
          <div className='overflow-hidden'>
            <div
              ref={containerRef}
              onScroll={onScroll}
              className='scrollbar-none flex w-full gap-6 overflow-x-auto scroll-smooth pt-6 pb-8 transition-opacity duration-500'
              style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
              role='list'
              aria-label='Categories list'
            >
              {categories.map(category => (
                <div
                  key={category.id}
                  className='w-[calc(50%-12px)] shrink-0 transition-transform duration-300 hover:scale-[1.02] sm:w-[calc(33.333%-16px)] md:w-[calc(25%-18px)] lg:w-[calc(20%-19.2px)]'
                  role='listitem'
                >
                  <article className='relative size-full'>
                    <div className='group relative h-0 w-full overflow-hidden rounded-full pb-[133.33%] shadow-md transition-all duration-300 hover:shadow-lg'>
                      <div className='absolute inset-0 size-full'>
                        <img
                          src={category.image}
                          alt={category.alt}
                          className='size-full object-cover transition-transform duration-300 group-hover:scale-105'
                          loading='lazy'
                          width={300}
                          height={400}
                        />
                        <div className='absolute inset-0 bg-linear-to-t from-black/70 via-black/10 to-transparent' />
                        <div className='absolute start-0 end-0 bottom-0 p-4 text-center'>
                          <h3 className='text-sm font-medium text-white sm:text-base md:text-lg'>{category.title}</h3>
                        </div>
                      </div>
                    </div>
                  </article>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  )
}
